  "type": "object",
  "properties": {
    "tagline": {
      "type": "string",
      "description": "Generate a unique and memorable phrase that captures the essence of the product and its primary benefit. "
    },
    "positioning_statement": {
      "type": "string",
      "description": "A 2-3 sentence statement that clearly defines what the product is, what it does, who it's for, the impact it delivers, and its competitive advantages."
    },
    "unique_value_proposition": {
      "type": "string",
      "description": "List 4-6 substantiating claims as bullet points explaining the function of key features, how the product delivers value, and how it's superior to alternatives."
    }
  },
  "required": ["tagline", "positioning_statement", "unique_value_proposition"]
}

parameters.jsCode:
// Get the structured output from the Basic LLM Chain node
const output = $input.first().json.output;

// Extract the three fields
const tagline = output.tagline || '';
const positioningStatement = output.positioning_statement || '';
const uniqueValueProposition = output.unique_value_proposition || '';

// Combine into formatted markdown text
let formattedText = '';

if (tagline) {
  formattedText += '# Product Tagline\n\n' + tagline + '\n\n';
}

if (positioningStatement) {
  formattedText += '# Positioning Statement\n\n' + positioningStatement + '\n\n';
}

if (uniqueValueProposition) {
  formattedText += '# Unique Value Proposition\n\n' + uniqueValueProposition + '\n\n';
}

// Return formatted text
return { formatted_text: formattedText };

